script:
export const meta = {
  name: 'pass6-verify-and-converge',
  description: 'Pass-6: re-verify 4 split findings (2-agent) + light convergence assessment',
  phases: [{ title: 'ReVerify' }, { title: 'Converge' }, { title: 'Synthesis' }],
}
const ROOT='/Users/[REDACTED]/hc-assay'
const SPLITS=[{"id": "H-005", "severity": "medium", "file": "src/assay_engine/reasoning/seam.py", "line": "414-503", "title": "HIGH_STAKES tier lacks the output-length cap that BULK enforces (asymmetric runaway-generation guard)", "description": "Verified: BULK always sets num_predict=BULK_NUM_PREDICT (seam.py:99, 368) and its docstring calls this 'the real guard' because a wall-clock timeout cannot interrupt a call already blocked in generation. _high_stakes_complete (seam.py:414-503) builds ClaudeAgentOptions with NO max-output-tokens equivalent \u2014 grep for max_tokens in seam.py returns nothing. A runaway BULK generation is bounded by tokens AND wall-clock; a runaway HIGH_STAKES generation is bounded only by anyio.fail_after(HIGH_STAKES_TIMEOUT). The cheaper/safer bound was applied only to the local tier, and HIGH_STAKES is the one consuming the fixed-cost subscription budget. The asymmetry is the same the BULK docstring argues against.", "poc": "A BULK call cannot emit more than ASSAY_BULK_NUM_PREDICT (2048) tokens. The parallel HIGH_STAKES call has no analogous bound: a prompt eliciting a very long completion runs until HIGH_STAKES_TIMEOUT (300s default), consuming the full subscription turn and a bounded-pool worker slot.", "suggested_fix": "Add an ASSAY_HIGH_STAKES_MAX_TOKENS cap and pass it to ClaudeAgentOptions (or the SDK's max-output-tokens option), mirroring num_predict. If the Agent SDK cannot bound output, document the asymmetry explicitly in the HIGH_STAKES docstring the way BULK's is documented."}, {"id": "H-006", "severity": "medium", "file": "src/assay_engine/methodology/discovery.py", "line": "69-165", "title": "discover_and_confirm lacks the on_step provenance hook that adjudicate_with_baseline has (asymmetric audit-trail wiring)", "description": "The two parallel firewall runners (discovery's own docstring calls itself 'the mirror of adjudication') were hardened asymmetrically for per-step provenance. adjudicate_with_baseline takes on_step: Callable[[Hypothesis, Verdict], None] | None (adjudication.py:193, 264-267) so a caller can record each pre-registered hypothesis+verdict to the hash-chained trail as each happens (#93), preserving GOVERNANCE \u00a73's 'recorded before the next step runs' ordering. discover_and_confirm (discovery.py:69-165) has no such hook: a standalone discovery study can only batch-record after the whole loop returns, losing the append-before-next-step ordering its twin enforces.", "poc": "adjudicate_with_baseline(..., on_step=lambda h,v: trail.record(...)) lands each verdict in confirmation order. discover_and_confirm(corpus, split, discover=..., confirm=..., authority=...) accepts no on_step, so a standalone study records verdicts only after the loop returns or by re-implementing the loop.", "suggested_fix": "Add an `on_step: Callable[[Hypothesis, Verdict], None] | None = None` parameter to discover_and_confirm and invoke it after each verdict is validated (right after the misattribution check at discovery.py:164), mirroring adjudication.py:264-267."}, {"id": "H-019", "severity": "low", "file": ".github/workflows/ci.yml", "line": "1", "title": "No concurrency group \u2014 superseded PR pushes keep running and audit/lockfile-compile can race", "description": "Verified: ci.yml has no concurrency block, so every push to an open PR spawns the full matrix without cancelling the prior in-flight run. Beyond wasted minutes, two overlapping audit runs on the same branch both run lockfile resolution / 'pip install -e .' and upload identically-named SBOM/license artifacts that can race. On a single dedicated compute node this compounds contention with the reasoning/checkpoint pools.", "poc": "grep -n concurrency .github/workflows/ci.yml -> no match. Push twice in quick succession to a PR; both runs execute to completion.", "suggested_fix": "Add a top-level concurrency: { group: ${{ github.workflow }}-${{ github.ref }}, cancel-in-progress: true } so a newer commit cancels the stale run and only one audit/lockfile-compile executes per ref."}, {"id": "H-020", "severity": "low", "file": ".github/workflows/ci.yml", "line": "117-168", "title": "pip-audit / SBOM each re-fetch the advisory DB and re-resolve \u2014 a network blip fails the 'reproducible' audit gate non-reproducibly", "description": "The audit job invokes pip-audit multiple times (gate at line 131, SBOM generation at line 151) plus a license-gate install, each reaching the OSV vuln DB / PyPI at run time. The stated goal is a reproducible supply-chain gate, but the result still depends on live availability of those services: a transient OSV/PyPI outage fails a commit that passed yesterday \u2014 the same non-reproducibility class the version pins were meant to remove. There is no retry, no vuln-DB caching, and the SBOM step re-runs the whole audit instead of reusing the gate's result.", "poc": "The gate step (line 131) and SBOM step (line 151) both run pip-audit against requirements.lock, each performing its own vulnerability-service lookup; no --cache-dir reuse or retry wrapper. An OSV/PyPI 5xx during any fails the required audit job.", "suggested_fix": "Run pip-audit once with --cache-dir (or a pinned/cached vuln DB), emit both the pass/fail and the CycloneDX SBOM from that single invocation, and wrap network steps in a bounded retry \u2014 halving PyPI/OSV calls and removing the duplicate live resolution from the reproducible gate."}]
const V={type:'object',required:['finding_id','confirmed','reasoning'],
  properties:{finding_id:{type:'string'},confirmed:{type:'boolean'},reasoning:{type:'string'}}}
const FIND={type:'object',required:['findings'],properties:{findings:{type:'array',items:{
  type:'object',required:['id','severity','file','line','title','description','poc','suggested_fix'],
  properties:{id:{type:'string'},severity:{type:'string',enum:['critical','high','medium','low']},
    file:{type:'string'},line:{type:['integer','string']},title:{type:'string'},
    description:{type:'string'},poc:{type:'string'},suggested_fix:{type:'string'}}}}}}

// Phase 1: re-verify the 4 split findings with fresh 2-agent pairs.
phase('ReVerify')
const vp=(f,n)=>`You are verifier #${n}, independent. This finding got a SPLIT verdict last round (one agent confirmed, one rejected). Read the ACTUAL code at ${ROOT} and decide independently if it is a TRUE production-readiness problem worth fixing in current code (5 hardening passes applied). confirmed=true only if real, reproducible, and genuinely worth a fix (not speculative/by-design/elective-nicety-with-no-real-risk).\n\n${f.id}: ${f.title}\nFile: ${f.file}:${f.line}\nDescription: ${f.description}\nPoC: ${f.poc}\nSuggested fix: ${f.suggested_fix}`
const reverify=await pipeline(SPLITS,
  f=>parallel([
    ()=>agent(vp(f,1),{label:'rvA:'+f.id,phase:'ReVerify',schema:V}),
    ()=>agent(vp(f,2),{label:'rvB:'+f.id,phase:'ReVerify',schema:V}),
  ]),
  (vs,f)=>{const [a,b]=vs.filter(Boolean); return {finding:f, both:a&&b&&a.confirmed&&b.confirmed,
    a:a?{c:a.confirmed,why:a.reasoning}:null, b:b?{c:b.confirmed,why:b.reasoning}:null}})

// Phase 2: a light fresh assessment (3 assessors) to confirm convergence — expect ~0 new highs.
phase('Converge')
const DIMS=[
  `Fresh adversarial security + data-sovereignty + concurrency audit of ${ROOT} (5 passes hardened). Report ONLY genuine, currently-reproducible production-readiness defects with file:line. Expect to find little — do not manufacture nits. JSON id (CV-S-N).`,
  `Fresh adversarial methodology-integrity + reliability audit of ${ROOT}/src/assay_engine (5 passes hardened). ONLY genuine reproducible defects, file:line. Expect little. JSON id (CV-M-N).`,
  `Fresh adversarial CI/supply-chain + observability + packaging audit of ${ROOT} (5 passes hardened). ONLY genuine reproducible defects, file:line. Expect little. JSON id (CV-O-N).`,
]
const raw=await parallel(DIMS.map((p,i)=>()=>agent(p,{label:'converge:'+i,phase:'Converge',schema:FIND})))
const fresh=raw.filter(Boolean).flatMap(r=>r.findings)
log('Fresh assessment surfaced '+fresh.length+' candidate(s) (pre-refutation).')

// Self-refute the fresh ones.
const REF={type:'object',required:['id','survives','reasoning'],properties:{id:{type:'string'},survives:{type:'boolean'},reasoning:{type:'string'}}}
const refuted=await parallel(fresh.map(f=>()=>agent(
  `Adversarial refuter: ASSUME this finding is FALSE; disprove it from the code at ${ROOT}. survives=true only if you genuinely cannot.\n${f.id}: ${f.title}\n${f.file}:${f.line}\n${f.description}\nPoC: ${f.poc}`,
  {label:'refute:'+f.id,phase:'Converge',schema:REF}).then(v=>({f,v}))))
const survivors=refuted.filter(Boolean).filter(r=>r.v&&r.v.survives).map(r=>r.f)

phase('Synthesis')
const splitConfirmed=reverify.filter(Boolean).filter(r=>r.both).map(r=>r.finding)
log('Split re-confirmed (both agents): '+splitConfirmed.length+'/4; fresh survivors: '+survivors.length)
return {
  split_reverify: reverify.filter(Boolean).map(r=>({id:r.finding.id, both_confirmed:r.both, a:r.a, b:r.b})),
  split_confirmed: splitConfirmed,
  fresh_raw: fresh.length, fresh_survivors: survivors,
}
